/// start mutil cores
#[allow(unused)]
pub fn start_harts(hart_id: usize) {
    for i in 0..MAX_HARTS {
        if i == hart_id {
            continue;
        }
        hart_start(i, HART_START_ADDR);
    }
}

/// Clear BSS segment at start up.
pub fn clear_bss() {
    unsafe extern "C" {
        fn _sbss();
        fn _kbss();
        fn _ebss();
    }
    unsafe {
        let start = _kbss as usize as *mut u64;
        let end = _ebss as usize as *mut u64;

        println!("s-kbss: {:#x} -  {:#x}", _sbss as usize, _kbss as usize);
        println!("k-ebss: {:#x} -  {:#x}", _kbss as usize, _ebss as usize);

        let len = end.offset_from(start) as usize;
        core::slice::from_raw_parts_mut(start, len).fill(0);

        // Handle any remaining bytes if the length is not a multiple of u64
        let start_byte = start as *mut u8;
        let len_bytes = _ebss as usize - _kbss as usize;
        if len_bytes % 8 != 0 {
            let offset = len * 8;
            core::slice::from_raw_parts_mut(start_byte.add(offset), len_bytes - offset).fill(0);
        }
    }
}

use alloc::vec::Vec;

core::arch::global_asm!(include_str!("linkapp.asm"));

/// get number of apps
pub fn get_num_app() -> usize {
    unsafe extern "C" {
        fn _num_app();
    }
    unsafe { (_num_app as usize as *const usize).read_volatile() }
}

/// get data of apps
pub fn get_app_data(app_id: usize) -> &'static [u8] {
    unsafe extern "C" {
        fn _num_app();
    }
    let num_app_ptr = _num_app as usize as *const usize;
    let num_app = get_num_app();
    let app_start = unsafe { core::slice::from_raw_parts(num_app_ptr.add(1), num_app + 1) };
    assert!(app_id < num_app);
    unsafe {
        core::slice::from_raw_parts(
            app_start[app_id] as *const u8,
            app_start[app_id + 1] - app_start[app_id],
        )
    }
}

pub fn init() {
    let num_app = get_num_app();
    unsafe extern "C" {
        fn _app_names();
    }
    let mut start = _app_names as usize as *const u8;
    let mut v = Vec::with_capacity(num_app);
    unsafe {
        for _ in 0..num_app {
            let mut end = start;
            while end.read_volatile() != b'\0' {
                end = end.add(1);
            }
            let slice = core::slice::from_raw_parts(start, end as usize - start as usize);
            let str = core::str::from_utf8(slice).unwrap();
            v.push(str);
            start = end.add(1);
        }
        APP_NAMES = Some(v);
    }
}

static mut APP_NAMES: Option<Vec<&'static str>> = None;

#[allow(unused, static_mut_refs)]
pub fn get_app_data_by_name(name: &str) -> Option<&'static [u8]> {
    let app_names = unsafe { APP_NAMES.as_ref().unwrap() };
    let num_app = get_num_app();
    (0..num_app)
        .find(|&i| app_names[i] == name)
        .map(get_app_data)
}

