/// TLB shootdown for the specified address range.
pub fn tlb_shootdown(addr: usize, length: usize) {
    sbi_rt::remote_sfence_vma_asid(
        sbi_rt::HartMask::from_mask_base(0, usize::MAX),
        addr,
        length,
        0,
    );
}

